class BookMyShow:

    def __init__(self, n: int, m: int):
        self.n = n
        self.m = m
        self.seats = [[True] * m for _ in range(n)]

    def gather(self, k: int, maxRow: int) -> List[int]:
        for row in range(maxRow + 1):
            if row >= self.n:
                return []
            if all(self.seats[row][i] for i in range(min(k, self.m - 1), min(k, self.m - 1) + k)):
                return [row, min(k, self.m - 1)]
        return []

    def scatter(self, k: int, maxRow: int) -> bool:
        for row in range(maxRow + 1):
            if row >= self.n:
                return False
            if all(self.seats[row][i] for i in range(min(k, self.m - 1), min(k, self.m - 1) + k)):
                for i in range(min(k, self.m - 1), min(k, self.m - 1) + k):
                    self.seats[row][i] = False
                return True
        return False
